if base < 2:
        raise ValueError("Base must be at least 2.")
    if x == 0:
        return '0'
    negative = x < 0
    x = abs(x)
    digits = []
    while x:
        digits.append(str(x % base))
        x //= base
    if negative:
        digits.append('-')
    return ''.join(reversed(digits))
